&lt;p&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;P&lt;/mi&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;r&lt;/mi&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;o&lt;/mi&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;o&lt;/mi&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;f&lt;/mi&gt;&lt;mo&gt;:&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\mathrm{Proof:}&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.6944em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathrm&#34; style=&#34;margin-right:0.07778em;&#34;&gt;Proof&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;:&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br /&gt;
$$&lt;br /&gt;
\begin&lt;ruby&gt;align*}
		\alpha&lt;rp&gt;(&lt;/rp&gt;&lt;rt&gt;T\Gamma_n\alpha&amp;amp;=\sum_{i,j&lt;/rt&gt;&lt;rp&gt;)&lt;/rp&gt;&lt;/ruby&gt;a_ia_j\gamma_&lt;ruby&gt;i-j}\\
		&amp;amp;=\sum_{i,j}a_ia_j\mathbb{E}(\left[X_i-\mu\right]\left[X_j-\mu\right])\\
		&amp;amp;=\mathbb{E}\left(\sum_{i,j}a_ia_j\left(X_i-\mu\right)(X_j-\mu)\right)\\
		&amp;amp;=\mathbb{E}\left(\sum_{i}a_i\left(X_i-\mu\right)\sum_ja_j(X_j-\mu)\right)\\
		&amp;amp;=\mathbb{E}\left(\left[\sum_ia_i(X_i-\mu)\right]&lt;rp&gt;(&lt;/rp&gt;&lt;rt&gt;2\right)\\
		&amp;amp;=\mathrm{D&lt;/rt&gt;&lt;rp&gt;)&lt;/rp&gt;&lt;/ruby&gt;\left(\sum_{i}a_i(X_i-\mu)\right)\geq 0&lt;br /&gt;
\end{align*}&lt;br /&gt;
$$&lt;/p&gt;
