&gt;s&lt;/mi&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;/mrow&gt;&lt;mrow&gt;&lt;mn&gt;2&lt;/mn&gt;&lt;mi&gt;π&lt;/mi&gt;&lt;/mrow&gt;&lt;/mfrac&gt;&lt;msup&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mrow&gt;&lt;mo&gt;−&lt;/mo&gt;&lt;mstyle displaystyle=&#34;false&#34; scriptlevel=&#34;0&#34;&gt;&lt;mfrac&gt;&lt;mrow&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mo&gt;−&lt;/mo&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;msup&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;mn&gt;2&lt;/mn&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;mn&gt;4&lt;/mn&gt;&lt;/mfrac&gt;&lt;/mstyle&gt;&lt;/mrow&gt;&lt;/msup&gt;&lt;mo mathvariant=&#34;normal&#34;&gt;≠&lt;/mo&gt;&lt;mn&gt;0&lt;/mn&gt;&lt;/mrow&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;/mtr&gt;&lt;/mtable&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\begin{align*}
\mathrm{Cov}(X_t,X_s)&amp;amp;=\mathbb{E}(X_t,X_s)\\
&amp;amp;=\int_{\mathbb{R}}\frac{T}{2\pi}e^{-\tfrac{(t+T)^2}{2}-\tfrac{(s+T)^2}{2}}\mathrm{d}T\\
&amp;amp;=\frac{1}{\sqrt{2\pi}}\int_{\mathbb{R}}\frac{T}{\sqrt{2\pi}}e^{-\tfrac{2T^2+2(s+t)T+s^2+t^2}{2}}\mathrm{d}T\\
&amp;amp;=\frac{1}{\sqrt{2\pi}}e^{-\tfrac{s^2+t^2}{2}}\int_{\mathbb{R}}\frac{T}{\sqrt{2\pi}}e^{-T^2-(s+t)T}\mathrm{d}T\\
&amp;amp;=\frac{1}{\sqrt{2\pi}}e^{-\tfrac{s^2+t^2}{2}+\tfrac{(s+t)^2}{4}}\int_{\mathbb{R}}\frac{T}{\sqrt{2\pi}}e^{-(T+\tfrac{s+t}{2})^2}\mathrm{d}T\\
&amp;amp;=\frac{1}{\sqrt{\pi}}e^{-\tfrac{(s-t)^2}{4}}\,\mathbb{E}({\small N(-\frac{s+t}{2},\frac{1}{\sqrt{2}})})\\
&amp;amp;=-\frac{s+t}{2\pi}e^{-\tfrac{(s-t)^2}{4}}\neq0
\end{align*}
